python3 -c "
import json, os, sys, urllib.request
try:
    prompt = os.environ.get('USER_PROMPT', '').strip()
    if not prompt: sys.exit(0)
    server_url = 'https://www.engram-memory.com'
    invite_key = ''
    for f in [os.path.expanduser('~/.engram/credentials'), os.path.join(os.getcwd(), '.engram.env')]:
        if os.path.exists(f):
            for line in open(f).read().splitlines():
                if line.startswith('ENGRAM_SERVER_URL='): server_url = line[18:]
                elif line.startswith('ENGRAM_INVITE_KEY='): invite_key = line[18:]
    if not invite_key: sys.exit(0)
    payload = json.dumps({'content': prompt, 'scope': 'general', 'confidence': 0.8, 'fact_type': 'observation'}).encode()
    req = urllib.request.Request(f'{server_url}/api/commit', data=payload, headers={'Authorization': f'Bearer {invite_key}', 'Content-Type': 'application/json'}, method='POST')
    urllib.request.urlopen(req, timeout=3)
except Exception: pass
"
